# Version 2: mission-by-mission progression.
#
# Keep the legacy contact item ids above for old rooms and manual start_inventory,
# but new seeds place per-mission unlocks instead. Existing ids are never
# renumbered; appended ids start after the last legacy item/location id.
# APINTRO covers the combined INTRO/EIGHT boot sequence. Exposing EIGHT as its
# own AP location makes the server expect a second check that the game cannot
# safely report, so new seeds only use mission_give_me_liberty for that sequence.
data["location_ids"].pop("mission_8ball", None)
data["locations"] = [
    _loc for _loc in data["locations"] if _loc.get("id") != "mission_8ball"
]

_side_locations = [
    ("mission_rc1", "Portland"), ("mission_rc2", "Staunton"),
    ("mission_rc3", "Shoreside"), ("mission_rc4", "Portland"),
    ("mission_4x4_1", "Portland"), ("mission_4x4_2", "Staunton"),
    ("mission_4x4_3", "Shoreside"), ("mission_mayhem1", "Portland"),
    ("mission_meat1", "Portland"), ("mission_meat2", "Portland"),
    ("mission_meat3", "Portland"), ("mission_meat4", "Portland"),
]

_next_location_id = max(data["location_ids"].values()) + 1
for _loc_id, _region in _side_locations:
    if _loc_id not in data["location_ids"]:
        data["location_ids"][_loc_id] = _next_location_id
        _next_location_id += 1
    if not any(_loc["id"] == _loc_id for _loc in data["locations"]):
        data["locations"].append({"id": _loc_id, "chain": None, "region": _region})

_mission_unlock_by_location = {}
_next_item_id = max(data["item_ids"].values()) + 1
for _loc in data["locations"]:
    _loc_id = _loc["id"]
    if not _loc.get("chain") or _loc_id == "mission_8ball":
        continue
    _item = "unlock_" + _loc_id
    _mission_unlock_by_location[_loc_id] = _item
    if _item not in data["item_ids"]:
        data["item_ids"][_item] = _next_item_id
        _next_item_id += 1

data["mission_unlock_by_location"] = _mission_unlock_by_location
data["mission_unlock_items"] = list(_mission_unlock_by_location.values())
data["legacy_contact_unlocks"] = [
    item for item in data["progression"]
    if item not in ("unlock_commercial", "unlock_suburban")
]
data["progression"] = [
    "unlock_commercial",
    "unlock_suburban",
] + data["mission_unlock_items"]
data["victory_location"] = "mission_cat1"
